<template><el-card><template #header><b>新建申请</b></template><el-form ref="formRef" :model="form" :rules="rules" label-width="110px" style="max-width:720px"><el-form-item label="业务类型" prop="businessType"><el-select v-model="form.businessType" style="width:100%"><el-option v-for="t in types" :key="t" :label="t" :value="t"/></el-select></el-form-item><el-form-item label="标题" prop="title"><el-input v-model="form.title"/></el-form-item><el-form-item label="目标人员ID"><el-input-number v-model="form.targetPersonId" :min="1"/></el-form-item><el-form-item label="申请原因" prop="reason"><el-input v-model="form.reason" type="textarea" :rows="4"/></el-form-item><el-form-item label="备注"><el-input v-model="form.remark"/></el-form-item><el-form-item><el-button @click="$router.back()">取消</el-button><el-button type="primary" :loading="saving" @click="save">保存草稿</el-button></el-form-item></el-form></el-card></template>
<script setup>import{reactive,ref}from'vue';import{useRouter}from'vue-router';import{ElMessage}from'element-plus';import{createApplication}from'../../api/applications';const router=useRouter(),formRef=ref(),saving=ref(false),form=reactive({businessType:'KEY_POPULATION_REGISTER',title:'',targetPersonId:null,reason:'',remark:''});const types=['KEY_POPULATION_REGISTER','KEY_POPULATION_RELEASE','SENSITIVE_DATA_EXPORT'];const rules={businessType:[{required:true,message:'请选择业务类型'}],title:[{required:true,message:'请输入标题'}],reason:[{required:true,message:'请输入申请原因'}]};async function save(){await formRef.value.validate();saving.value=true;try{const r=await createApplication(form);ElMessage.success('草稿已创建');router.replace(`/applications/${r.applicationId}`)}finally{saving.value=false}}</script>
